import 'package:flutter_test/flutter_test.dart'; import 'package:googlepro/features/chat/state/chat_state.dart'; import 'package:googlepro/features/chat/model/chat_message.dart'; void main() { group('ChatState', () { test('ChatLoaded copyWith updates isTyping', () { const state = ChatLoaded(messages: []); final updated = state.copyWith(isTyping: true); expect(updated.isTyping, true); expect(updated.messages.isEmpty, true); }); test('ChatLoaded copyWith updates messages', () { const state = ChatLoaded(messages: []); final msg = ChatMessage(messageId: 'm1', sessionId: 's1', senderId: 'u1', senderName: 'A', type: MessageType.text, timestamp: DateTime.now()); final updated = state.copyWith(messages: [msg]); expect(updated.messages.length, 1); }); }); }